    self.stChallengeText = self:getChildWindow("BedWarLicenseSeasonTask-Chellenge-Text", GUIType.StaticText)

    local llTaskList = self:getChildWindow("BedWarLicenseSeasonTask-List", GUIType.Layout)
    self.lvTaskList = IGUIListView.new("BedWarLicenseSeasonTask-Season-Task-List-Grid", llTaskList, nil, Orientation.Horizontal)
    self.lvTaskList:setArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 1, 0 })
    self.lvTaskList:setItemSpace(38)
    self.taskListAdapt = require "common.ui.adapter.LicenseSeasonTaskAdapt".new()
    local taskParentWith = self.lvTaskList:getWidth()
    local taskParentHigh = self.lvTaskList:getHeight()
    local itemWidth = (taskParentWith - 2 * 38) / 3.5
    self.taskListAdapt:setItemSize(itemWidth, taskParentHigh)
    self.lvTaskList:setAdapter(self.taskListAdapt)

    local llMoney = self:getChildWindow("BedWarLicenseSeasonTask-Money", GUIType.Layout)
    self.lvMoney = IGUIListView.new("BedWarLicenseSeasonTask-Money-List", llMoney, nil, Orientation.Horizontal)
    self.lvMoney:setItemSpace(30)

    self.llHorn = GUICurrency.new("BedWarCurrency.json")
    self.llHorn:onDataChanged({ ItemId = 0, RealId = Define.Money.HORN })
    self.lvMoney:addItem(self.llHorn)

    self.llDiamond = GUICurrency.new("BedWarCurrency.json")
    self.llDiamond:onDataChanged({ ItemId = 0, RealId = Define.Money.DIAMOND })
    self.lvMoney:addItem(self.llDiamond)

    local seasonConfig = LicenseConfig:getSeasonConfigBySeason(GUILicense.seasonDate)
