function UILicenseSeasonTask:onShow()
    self.taskList = GUILicense.seasonTaskList

    self.lvTaskList:clearItems()
    self.taskListAdapt:setData(self.taskList)
end

function UILicenseSeasonTask:updateData()
    self.taskList = GUILicense.seasonTaskList
    self.taskListAdapt:setData(self.taskList)
    local taskNum = 0
    local finishNum = 0
    for _, task in pairs(self.taskList) do
        local taskConfig = TaskConfig:getTaskById(task.taskId)
        if taskConfig then
            if taskConfig.NextTaskId == 0 and task.status == 4 then
                finishNum = finishNum + 1
            end
            taskNum = taskNum + 1
        end
    end
    local text = "▢FFF4EA54" .. finishNum .. "▢FFFFFFFF/" .. taskNum
    GUILicense.stTaskChallengeNum:SetText(text)
    self.stChallengeText:SetText(Lang:getString("gui_bed_war_license_season_task_chellenge") .. ": "  .. text)
end

function UILicenseSeasonTask:onTick()
    self.llDiamond:onTick()
    self.llHorn:onTick()
end

function UILicenseSeasonTask:showRedPoint()
    for _, task in pairs(self.taskList) do
        if task.status == 3 or task.status == 4 then
            local taskConfig = TaskConfig:getTaskById(task.taskId)
            if taskConfig and taskConfig.NextTaskId ~= 0 then
                GUILicense.siRedPoint:SetVisible(true)
                return
            end
        end
    end
    GUILicense.siRedPoint:SetVisible(false)
    return
end

return UILicenseSeasonTask